1553	\section{Chebyshev domains and circle codes}\label{sec:cheb}
1554	
1555	The locator mechanism uses only two facts about $x\mapsto x^M$: the domain is a union of complete fibers, and fiber locators are value-translates of a single degree-$M$ polynomial.  Both transfer to Dickson--Chebyshev quotient chains, hence to the $x$-coordinate domains of circle groups used by circle STARKs \cite{HLP24}, and in principle to the isogeny chains of ECFFT \cite{ECFFT}.
1556	
1557	\begin{lemma}[Dickson quotient chain]\label{lem:chebchain}
1558	Let $p$ be odd, $N\mid p+1$ even, and $X_N:=\{\zeta+\zeta^{-1}:\zeta\in\mu_N(\F_{p^2})\}\subseteq\F_p$, of size $N/2+1$.  For $m\mid N$ let $D_m$ be the degree-$m$ monic Dickson polynomial, $D_m(\zeta+\zeta^{-1})=\zeta^m+\zeta^{-m}$.  Then $D_m(X_N)=X_{N/m}$, and for every $w\in X_{N/m}\setminus\{\pm2\}$ the fiber $D_m^{-1}(w)\cap X_N$ has exactly $m$ elements and locator polynomial exactly $D_m(X)-w$.
1559	\end{lemma}
1560	
1561	\begin{proof}
1562	$D_m(\zeta+\zeta^{-1})=\xi+\xi^{-1}$ iff $\zeta^m\in\{\xi,\xi^{-1}\}$; for $\xi\ne\xi^{-1}$ this gives $2m$ values of $\zeta\in\mu_N$ pairing into $m$ distinct values of $\zeta+\zeta^{-1}$, all roots of the degree-$m$ polynomial $D_m(X)-w$, which is therefore their monic locator.
1563	\end{proof}
1564	
1565	\begin{theorem}[Quotient cores for Chebyshev domains]\label{thm:chebqcore}
1566	Let $C=\RS[\F_p,X_N,k]$ with $m\mid k$, $\kappa=k/m$, $\kappa\le\frac N{2m}-3$, and $1\le\sigma<m$.  Then
1567	\[
1568	        \Lst\Big(C,\ 1-\frac{k+\sigma}{N/2+1}\Big)\ \ge\ \binom{N/(2m)-2}{\kappa}.
1569	\]
1570	\end{theorem}
1571	
1572	\begin{proof}
1573	Fix $w_0\in X_{N/m}\setminus\{\pm2\}$ with fiber $F_0$, choose $T\subset F_0$ with $|T|=\sigma$, and set $Y:=D_m(X)^{\kappa}L_T(X)$ with $L_T=\prod_{t\in T}(X-t)$.  For each $A\subseteq X_{N/m}\setminus\{\pm2,w_0\}$ of size $\kappa$, the union of fibers over $A$ has locator $L_A=\prod_{w\in A}(D_m(X)-w)$ by \cref{lem:chebchain}, and as a polynomial in $D_m$,
1574	\[
1575	        D_m^{\kappa}-L_A=e_1(A)D_m^{\kappa-1}-e_2(A)D_m^{\kappa-2}+\cdots,
1576	\]
1577	of degree at most $m(\kappa-1)=k-m$.  Thus $P_A:=L_T\cdot(D_m^\kappa-L_A)$ has degree at most $\sigma+k-m<k$, hence is a codeword, and $Y-P_A=L_TL_A$ vanishes on $T\cup D_m^{-1}(A)$, an agreement set of size $\sigma+m\kappa=k+\sigma$.  Distinct $A$ give distinct $P_A$.  (The pullback form of $Y$ is essential: unlike $X^M-\alpha$, the polynomial $D_m$ has internal terms, so $X^k-L_A$ would only have degree $k-2$.)
1578	\end{proof}
1579	
1580	\begin{proposition}[Slack-one canonical stratum on a Chebyshev quotient]\label{prop:chebslack}
1581	With the notation of \cref{thm:chebqcore}, consider the line with $f=D_m^{\kappa+1}$ and $g=D_m^{\kappa}$ as words on $X_N$, and let $X'=X_{N/m}\setminus\{\pm2\}$, $N'=|X'|=\frac N{2m}-1$.  For every $A\subseteq X'$ with $|A|=\kappa+1\le N'$, the parameter $z=-e_1(A)$ is support-wise MCA-bad at radius $1-\frac{k+m}{N/2+1}$.  Consequently, by Dias da Silva--Hamidoune \cite{DH94},
1582	\[
1583	        \emca\Big(C,\ 1-\frac{k+m}{N/2+1}\Big)\ \ge\ \frac{\min\{p,\ (\kappa+1)(N'-\kappa-1)+1\}}{p}.
1584	\]
1585	\end{proposition}
1586	
1587	\begin{proof}
1588	Let $S=D_m^{-1}(A)\cap X_N$, of size $m(\kappa+1)=k+m$.  In the variable $u=D_m$, the polynomial $u^{\kappa+1}-e_1(A)u^{\kappa}-\prod_{w\in A}(u-w)$ has degree at most $\kappa-1$, so $P:=D_m^{\kappa+1}-e_1(A)D_m^{\kappa}-L_A$ is a codeword, and $f+zg-P=L_A$ vanishes on $S$: the line is $S$-close.  But $g=D_m^\kappa$ cannot be explained on $S$: for any codeword $c_g$, the difference $D_m^\kappa-c_g$ is monic of degree exactly $k$ and would need $k+m>k$ roots.  So condition (ii) of \cref{def:mca} holds at $S$, and $z=-e_1(A)$ is bad.  The count is the restricted sumset bound applied to the arbitrary set $X'\subset\F_p$.
1589	\end{proof}
1590	
1591	\begin{corollary}[Failure on circle $x$-coordinate domains at Mersenne-$31$ parameters]\label{cor:circle}
1592	Let $p=2^{31}-1$, so the circle group has order $p+1=2^{31}$ and every $X_N$ with $N\mid 2^{31}$ is available.  For $N\ge2^{19}$, $m=N/2^{18}$, and $k=\rho(N/2+1)+O(1)$ at $\rho=1/2$ with $m\mid k$:
1593	\[
1594	        (\kappa+1)(N'-\kappa-1)+1\ \approx\ \tfrac14(2^{17})^2\ =\ 2^{32}\ >\ p,
1595	\]
1596	so the slack-one canonical stratum already has error one at radius approximately $1-\rho-2^{-17}$.  The up-to-capacity hope thus fails for the Reed--Solomon constituents on circle-group $x$-coordinate domains exactly as on multiplicative smooth domains.
1597	\end{corollary}
1598	
1599	\begin{remark}[Circle codes proper, and the general isogeny transfer]\label{rem:isogeny}
1600	Circle codes decompose as $f(x,y)=f_0(x)+yf_1(x)$ with $f_0,f_1$ supported on $x$-coordinate domains \cite{HLP24}; the stratum above lives in the even part, and carrying the full bivariate MCA bookkeeping through this decomposition is routine but deferred.  More generally, the proofs above used only that the domain is a union of complete fibers of a chain of low-degree maps whose fiber locators are value-translates of one polynomial: multiplicative powers, Dickson--Chebyshev maps, linearized polynomials, and the $2$-isogeny chains of ECFFT \cite{ECFFT} all qualify.  This gives structural content to the degenerate-code characterization requested in \cite{ABF26}: degeneracy is a large cover structure compatible with the degree filtration.
1601	\end{remark}
