708	\[
709	        L_A(X)\ :=\ \prod_{b\in A}(X^a-b)\ =\ X^{k+ta}+\sum_{j=1}^t(-1)^je_j(A)\,X^{k+(t-j)a}+R_A(X),
710	        \qquad\deg R_A<k,
711	\]
712	and $L_A$ vanishes on $S_A=\{x\in D:\ x^a\in A\}$, of size $k+ta$.  (Expand $\prod_b(Y-b)$ at $Y=X^a$: the displayed terms sit in degrees $a(\ell-j)$, and all remaining degrees are below $a(\ell-t)=k$.)
713	\end{lemma}
