727	\begin{proposition}[Coset collapse: symmetric slack is no slack]\label{prop:collapse}
728	Let $p>d$, $K\le Q$ of order $d$, $d\mid\ell$, and let $A$ be a union of $\ell/d$ distinct $K$-cosets.  Then $p_j(A)=0$ for all $d\nmid j$ --- in particular $e_1(A)=\cdots=e_{d-1}(A)=0$ automatically --- and $e_d(A)=(-1)^{d-1}\sum_iy_i$ with $y_1,\dots,y_{\ell/d}$ the distinct $d$-th powers of coset representatives.  Hence the union-of-coset part of $V_d(Q,\ell)$ equals, up to an explicit nonzero scalar, the slack-\emph{one} value set $m^{\wedge}(Q^d)$ at quotient order $N/d$, $m=\rho(N/d)+1$: subgroup-symmetric witnesses produce nothing beyond the one-condition ladder.
729	\end{proposition}
730	
731	\begin{proof}
732	$\sum_{\kappa\in K}(x\kappa)^j=x^j\sum_\kappa\kappa^j$, which is $dx^j$ if $d\mid j$ and $0$ otherwise; sum over cosets, convert by Newton ($p>d$); distinct cosets biject with distinct $d$-th powers; and $\ell/d=\rho(N/d)+1$ at $\ell=\rho N+d$.
733	\end{proof}
734	
735	New slack content therefore requires \emph{asymmetric} witnesses with vanishing leading symmetric functions.  The next two theorems prove that the two global models which decide no-slack questions --- lifting to characteristic zero, and lifting to short digit ranges --- cannot see them, even at $t=2$.
736	
737	\begin{theorem}[Cyclotomic rigidity]\label{thm:rigidcyclo}
738	Let $N=2^s$ and $A\subseteq\mu_N\subseteq\Z[\zeta_N]$ with $p_1(A)=0$ in $\Z[\zeta_N]$.  Then $A$ is a union of antipodal pairs $\{\omega,-\omega\}$.  Consequently every characteristic-zero witness for $V_2$ is of coset type, and the characteristic-zero slack-$2$ value set is exactly the ladder rung $2\cdot m^{\wedge}(\mu_{N/2})$.
739	\end{theorem}
740	
741	\begin{proof}
742	In the power basis $1,\zeta,\dots,\zeta^{N/2-1}$, $\sum_{a\in A}a=\sum_jc_j\zeta^j$ with $c_j=\mathbf1[\zeta^j\in A]-\mathbf1[-\zeta^j\in A]\in\{-1,0,1\}$; vanishing forces $c\equiv0$, i.e.\ each antipodal pair is contained in or disjoint from $A$.  Then $p_2(A)=2\sum_{\rm pairs}\zeta^{2j}$.
743	\end{proof}
744	
745	\begin{theorem}[Digit rigidity on Fermat fields]\label{thm:rigidfermat}
746	Let $p=2^M+1$ be a Fermat prime, $Q=\langle2\rangle=\{\pm2^j:0\le j<M\}\le\F_p^\times$, and $A\subseteq Q$ with $\sum_{a\in A}a\equiv0\pmod p$.  Then $A$ is a union of antipodal pairs.
747	\end{theorem}
748	
749	\begin{proof}
750	The sum lifts to $s=\sum_jc_j2^j$, $c_j\in\{-1,0,1\}$, with $|s|\le2^M-1<p$, so $s=0$; uniqueness of binary representations forces $c\equiv0$.
751	\end{proof}
752	
753	\begin{remark}[Where the difficulty lives]\label{rem:wall}
754	Asymmetric elements of $V_t$ require cancellations of size comparable to $p$ --- genuinely modular, i.e.\ subgroup equidistribution.  \Cref{sec:pool} pushes equidistribution as far as current exponential-sum technology reaches; \cref{sec:rigidity} develops the characteristic-zero theory at every slack, which governs the deepest level; \cref{sec:boundary} proves where these methods stop.
755	\end{remark}
756	
757	\subsection{Certified slack thresholds, and curve transfer}
758	
759	\begin{lemma}[Dias da Silva--Hamidoune \cite{DH94}; polynomial-method proofs in \cite{ANR96,Alon99}]\label{lem:dsh}
760	For every $A\subseteq\F_p$ with $|A|=m$ and every $1\le h\le m$:
761	$|h^{\wedge}A|\ \ge\ \min\{p,\ h(m-h)+1\}$.
762	\end{lemma}
763	
764	\begin{corollary}[Certified slack at the root barrier]\label{cor:certified}
765	Let $0<\rho\le1/2$ and let $N_{\rm full}(p,n,\rho)$ be the smallest divisor $N\mid n$ with $\rho N\in\Z$, $\ell=\rho N+1\le N$, and $\ell(N-\ell)+1\ge p$.  For every divisor $N\ge N_{\rm full}$ with $\rho N\in\Z$:
766	\[
767	        \emca\Big(\RS[\F_p,D,\rho n],\ 1-\rho-\tfrac1N\Big)\ =\ 1,
768	\]
769	hence error one on the interval $[1-\rho-1/N_{\rm full},\,1]$, with $N_{\rm full}\le(1+o(1))\sqrt{p/\rho(1-\rho)}$ when such divisors exist (automatic on smooth $n$ of that size).  (\Cref{lem:dsh} makes $V_1(Q,\ell)=-\ell^{\wedge}Q=\F_p$; \cref{thm:slackt} at $t=1$; monotonicity for the interval.)

